    END IF;
    v_ex_id := gen_random_uuid();

    INSERT INTO exercises.exercise (id,name,difficulty,mechanics,force,unilateral,bodyweight,overall_risk,spotter_required,owner_user_id,visibility,status,translations,created_at,updated_at)
    VALUES (v_ex_id,'Lunge','beginner','compound','push',true,true,'low',false,NULL,'public','active',
        jsonb_build_object('it',jsonb_build_object('name','Affondo','description','Imposta una stance lunga e busto in asse, poi scendi verticalmente in controllo. Spingi dal piede avanti per risalire mantenendo ginocchio stabile e bacino fermo.'),
                           'en',jsonb_build_object('name','Lunge','description','Set a long stance and keep the torso stacked, then lower straight down under control. Push through the front foot to stand up, keeping the knee aligned and the pelvis stable.')),NOW(),NOW());

